patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..43f60d77bbb1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,42 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // smin(X + 1, Y) - smin(X, Y) --> X < Y ? 1 : 0
+  // This pattern represents the "step" at the min boundary.
+  if (MinMax->getIntrinsicID() == Intrinsic::smin) {
+    Value *X1, *Y1, *X2, *Y2;
+    // Match both operands as smin intrinsics
+    if (match(Op0, m_OneUse(m_SMin(m_Value(X1), m_Value(Y1)))) &&
+        match(Op1, m_OneUse(m_SMin(m_Value(X2), m_Value(Y2))))) {
+      // Check that the Y operands are the same
+      if (Y1 == Y2) {
+        // Check if X1 == X2 + 1
+        Value *X_base;
+        const APInt *C;
+        if (match(X1, m_Add(m_Value(X_base), m_APInt(C))) &&
+            X_base == X2 && C->isOne()) {
+          // Verify the add has NSW flag
+          auto *Add = dyn_cast<OverflowingBinaryOperator>(X1);
+          if (Add && Add->hasNoSignedWrap()) {
+            Value *Cmp = Builder.CreateICmp(ICmpInst::ICMP_SLT, X2, Y2);
+            return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                      ConstantInt::get(Ty, 0));
+          }
+        }
+        // Also check if X2 == X1 + 1 (reversed order)
+        if (match(X2, m_Add(m_Value(X_base), m_APInt(C))) &&
+            X_base == X1 && C->isOne()) {
+          auto *Add = dyn_cast<OverflowingBinaryOperator>(X2);
+          if (Add && Add->hasNoSignedWrap()) {
+            Value *Cmp = Builder.CreateICmp(ICmpInst::ICMP_SLT, X1, Y1);
+            return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                      ConstantInt::get(Ty, 0));
+          }
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

